import { Notification } from './notification.model';
import { Pool } from 'pg';

export interface INotificationRepository {
  create(notification: Omit<Notification, 'id' | 'createdAt' | 'isRead' | 'readAt'>): Promise<Notification>;
  findByRecipient(recipientId: string, unreadOnly?: boolean): Promise<Notification[]>;
  markAsRead(id: string): Promise<Notification>;
}

export class NotificationRepository implements INotificationRepository {
  constructor(private readonly pool: Pool) {}

  async create(notification: Omit<Notification, 'id' | 'createdAt' | 'isRead' | 'readAt'>): Promise<Notification> {
    const client = await this.pool.connect();
    try {
      const result = await client.query(
        `INSERT INTO notifications (
          recipient_id, sender_id, type, title, message, metadata
        ) VALUES ($1, $2, $3, $4, $5, $6)
        RETURNING *`,
        [
          notification.recipientId,
          notification.senderId,
          notification.type,
          notification.title,
          notification.message,
          notification.metadata
        ]
      );
      return this.mapRowToNotification(result.rows[0]);
    } finally {
      client.release();
    }
  }

  async findByRecipient(recipientId: string, unreadOnly: boolean = false): Promise<Notification[]> {
    let query = 'SELECT * FROM notifications WHERE recipient_id = $1';
    const params: any[] = [recipientId];

    if (unreadOnly) {
      query += ' AND is_read = false';
    }

    query += ' ORDER BY created_at DESC';

    const result = await this.pool.query(query, params);
    return result.rows.map(row => this.mapRowToNotification(row));
  }

  async markAsRead(id: string): Promise<Notification> {
    const client = await this.pool.connect();
    try {
      const result = await client.query(
        `UPDATE notifications 
         SET is_read = true, read_at = CURRENT_TIMESTAMP
         WHERE id = $1
         RETURNING *`,
        [id]
      );
      if (result.rows.length === 0) {
        throw new Error(`Notification with id ${id} not found`);
      }
      return this.mapRowToNotification(result.rows[0]);
    } finally {
      client.release();
    }
  }

  private mapRowToNotification(row: any): Notification {
    return {
      id: row.id,
      recipientId: row.recipient_id,
      senderId: row.sender_id,
      type: row.type,
      title: row.title,
      message: row.message,
      metadata: row.metadata,
      isRead: row.is_read,
      readAt: row.read_at,
      createdAt: row.created_at
    };
  }
